# Input Validation
def validate_string_input(value, max_length=200, pattern=None):
    if not isinstance(value, str):
        raise ValueError("Input must be a string")
    if len(value) > max_length:
        raise ValueError(f"Input exceeds maximum length of {max_length}")
    if pattern and not re.match(pattern, value):
        raise ValueError("Input contains invalid characters")
    return value.strip()

def validate_integer_input(value, min_val=None, max_val=None):
    if not isinstance(value, int):
        raise ValueError("Input must be an integer")
    if min_val is not None and value < min_val:
        raise ValueError(f"Value must be at least {min_val}")
    if max_val is not None and value > max_val:
        raise ValueError(f"Value must be at most {max_val}")
    return value

def validate_float_input(value, min_val=None, max_val=None):
    if not isinstance(value, (int, float)):
        raise ValueError("Input must be a number")
    value = float(value)
    if min_val is not None and value < min_val:
        raise ValueError(f"Value must be at least {min_val}")
    if max_val is not None and value > max_val:
        raise ValueError(f"Value must be at most {max_val}")
    return value

# Query Complexity Analysis
def calculate_query_complexity(node, complexity=0, depth=0):
    if depth > MAX_QUERY_DEPTH:
        raise ValueError(f"Query depth exceeds maximum of {MAX_QUERY_DEPTH}")
    
    if isinstance(node, graphql.language.ast.Field):
        complexity += 1
        if node.selection_set:
            for selection in node.selection_set.selections:
                complexity = calculate_query_complexity(selection, complexity, depth + 1)
    elif isinstance(node, graphql.language.ast.InlineFragment):
        if node.selection_set:
            for selection in node.selection_set.selections:
                complexity = calculate_query_complexity(selection, complexity, depth + 1)
    
    return complexity

def count_aliases(node, aliases=None):
    if aliases is None:
        aliases = set()
    
    if isinstance(node, graphql.language.ast.Field):
        if node.alias:
            aliases.add(node.alias.value)
        if node.selection_set:
            for selection in node.selection_set.selections:
                count_aliases(selection, aliases)
    elif isinstance(node, graphql.language.ast.InlineFragment):
        if node.selection_set:
            for selection in node.selection_set.selections:
                count_aliases(selection, aliases)
    
    return len(aliases)

