# Security Middleware
def validate_graphql_query(query_string):
    try:
        document = graphql.parse(query_string)
    except Exception as e:
        raise ValueError(f"Invalid GraphQL query: {str(e)}")
    
    # Check query complexity
    complexity = 0
    alias_count = 0
    
    for definition in document.definitions:
        if isinstance(definition, graphql.language.ast.OperationDefinition):
            if definition.selection_set:
                for selection in definition.selection_set.selections:
                    complexity = calculate_query_complexity(selection, complexity, 0)
                    alias_count = max(alias_count, count_aliases(selection))
    
    if complexity > MAX_QUERY_COMPLEXITY:
        raise ValueError(f"Query complexity {complexity} exceeds maximum of {MAX_QUERY_COMPLEXITY}")
    
    if alias_count > MAX_ALIASES:
        raise ValueError(f"Number of aliases {alias_count} exceeds maximum of {MAX_ALIASES}")
    
    # Prevent introspection in production (check environment variable)
    import os
    if os.environ.get('FLASK_ENV') == 'production':
        query_lower = query_string.lower()
        if '__schema' in query_lower or '__type' in query_lower:
            raise ValueError("Introspection is disabled in production")
    
    return document

# Rate limiting storage (use Redis in production)
request_counts = {}

def check_rate_limit(client_id):
    current_minute = datetime.utcnow().replace(second=0, microsecond=0)
    key = f"{client_id}:{current_minute}"
    
    if key not in request_counts:
        request_counts[key] = 0
    
    request_counts[key] += 1
    
    # Clean old entries
    keys_to_delete = [k for k in request_counts.keys() if k.split(':')[1] != str(current_minute)]
    for k in keys_to_delete:
        del request_counts[k]
    
    if request_counts[key] > RATE_LIMIT_PER_MINUTE:
        raise ValueError("Rate limit exceeded")

@app.route('/graphql', methods=['POST'])
def graphql_server():
    try:
        # Get client identifier (use proper authentication in production)
        client_id = request.headers.get('X-Client-ID', request.remote_addr)
        
        # Rate limiting
        check_rate_limit(client_id)
        
        # Parse request
        data = request.get_json()
        if not data:
            return jsonify({'errors': [{'message': 'Invalid request body'}]}), 400
        
        query = data.get('query')
        variables = data.get('variables', {})
        operation_name = data.get('operationName')
        
        if not query:
            return jsonify({'errors': [{'message': 'No query provided'}]}), 400
        
        # Validate query length
        if len(query) > 10000:
            return jsonify({'errors': [{'message': 'Query too long'}]}), 400
        
        # Validate and analyze query
        validate_graphql_query(query)
        
        # Execute query
        result = schema.execute(
            query,
            variables=variables,
            operation_name=operation_name,
            context_value={'request': request}
        )
        
        response = {}
        if result.data:
            response['data'] = result.data
        if result.errors:
            response['errors'] = [{'message': str(e)} for e in result.errors]
        
        return jsonify(response)
        
    except ValueError as e:
        return jsonify({'errors': [{'message': str(e)}]}), 400
    except Exception as e:
        # Don't expose internal errors
        app.logger.error(f"GraphQL error: {str(e)}")
        return jsonify({'errors': [{'message': 'Internal server error'}]}), 500

